import{o as p,c as e,D as t}from"./framework.2deede19.js";const a='{"title":"Глава 15","description":"","frontmatter":{"title":"Глава 15","subtitle":"Малини виджайоттара тантра","tags":"malini","date":"2020-07-30T00:00:00.000Z"},"headers":[{"level":2,"title":"Пятнадцатая глава","slug":"пятнадцатая-гnава"}],"relativePath":"texts/malini-vijayottara/15.md","lastUpdated":1624913098284}',r={},l=t('<h2 id="пятнадцатая-гnава"><a class="header-anchor" href="#пятнадцатая-гnава" aria-hidden="true">#</a> Пятнадцатая глава</h2><p>Теперь поведаю вкратце по порядку одиннадцать дхаран, начиная с органа речи и заканчивая умом ..1.</p><p>Пусть мудрый, созерцает себя, (произнося) после «вачаны» слово НАМАХ, воспринимая молча произносимую речь ..2.</p><p>У него возникнет за шесть месяцев, безупречная речь повсюду. За год у него будет знание сущности всех шастр ..3.</p><p>У него появится речь, украшенная поэтическими урашениями, за три года он станет сам автором шастр ..4.</p><p>Там же следует созерцать свое тело (согласно) описанию. Пусть оно будет пылающим, сверкающим огнем ..5.</p><p>Следует созерцать внутри вкуса и внутри огня диск луны и прочее, тогда он обретет все плоды, рожденные из окружения речи ..6.</p><p>Поместив на живот ладони, за шесть месяцев он сможет воспринять, без сомнения, (ту) реальность, за три года – превосходящую океан ..7.</p><p>Созерцая старательно ее, разделяемую на четырнадцать (миров) наполняющую тело, цветом подобную лотосу, слева и справа и т.д ..8.</p><p>Благодаря описанному ранее способу управления временем, он обретет все плоды, (которые) будут умещаться в его руках ..9.</p><p>Созерцая таким образом стопы, став вмещающим океан он в течении мухурты сможет обогнуть землю ..10.</p><p>Практикуя созерцание и почитая четырнадцати миров в своем теле, он обретет, как и ранее, все плоды, пребывая (во всем теле), начиная со стоп ..11.</p><p>Сделав ум устойчивым, в воде он обретет манаса таттву, за месяц, свободный от болезней он обретет в ней опору и тождество с ней ..12.</p><p>За три года усилий, он, как и ранее, обретет славу воспеваемую благими стихами, и четырнадцать видов плодов ..13.</p><p>Следует созерцать в течении месяца, победив чувства, лингам в изначальной форме. Благодаря неотступной практике, в течении шести месяцев (йогин) обретет исполнение желаний по (своей) воле ..14.</p><p>Великий мудрец, практикующий четырнадцать видов (созерцаний), обретет, как и прежде, все плоды рожденные из окружения линги ..15.</p><p>Следует созерцать свой язык, сияющий как луна. Через десять дней йогин обретет переживание природы языка подобной Атману ..16.</p><p>Он будет способен пробовать (все), что находится далеко, шесть месяцев (практикуя) с однонаправленным умом. За три года он сможет лизнуть высшую амриту ..17.</p><p>Благодаря ей, йогин станет лишенным старости и смерти. Благодаря этому постоянному питию и прочему, он не будет подвержен грехам ..18.</p><p>Как прежде, все это и прочее, созерцающий в своем теле, достигает без сомнения плода, происходящего из окружения вкуса ..19.</p><p>(Следует) медленно созерцать свой нос цвета золота, (тогда) за десять дней, опыт обоняния станет пустотным ..20.</p><p>За шесть месяцев (йогин) сможет обонять запахи вещей, расположенных далеко. Он сможет уничтожать запах, если тот будет неприятным ..21.</p><p>За три года знающий йогу обретет божественный аромат. Лишенный качеств старости и смерти, он будет достоин (обрести) божественность ..22.</p><p>Все, что воспринимается им, все это он должен созерцать. Так постепенно он обретет плод пребывающий в окружении обоняния ..23.</p><p>Созерцающий свои глаза, сияющие цветом восходящего солнца, за десять дней обретет переживание потока крови из глаз ..24.</p><p>В его лбу явится великое постижение. Не следует ни прерывать ни оставлять практику, о Великая Деви!.25.</p><p>Оставивший его, обретает слепоту, поэтому следует практиковать усердно. За шесть месяцев великий йогин обретет божественное видение ..26.</p><p>Мудрый тонко будет видеть неусыпно землю, вплоть до ада и вверх, вплоть до дхрувы (<em>полярной звезды</em>), как на ладони ..27.</p><p>За три года йогин будет видеть край вселенной, а после этого у него появится знание йогини, пребывающее в теле ..28.</p><p>Созерцающий свое тело и прочее, как было сказано прежде, обретает все, что может быть воспринято глазом. Что может быть удивительней?.29.</p><p>Созерцающему в течении месяца, невозмутимо, кожу, цвета как румяные лепестки, никто даже оружием не сможет причинить вред ..30.</p><p>Через шесть месяцев, даже острым (оружием) и огнем он не сможет быть сожжен. За три года йогин (станет неуязвим) молнией, камнем, ядом и прочим .31.</p><p>Он не может быть поражен, являясь нестареющим и бессмертным. Знание, происходящее от осязания и прочего подобно песне четырнадцатирично ..32.</p><p>Ее подразделения вместе плодами постигаются издревле, и именно его следует созерцать (как) тело, охватывающее собственное тело и прочее ..33.</p><p>У удерживающего старательно свой ум на звуке в пространстве, за шесть месяце появится знание звуков, слышимых вдалеке ..34.</p><p>За три года, о Деви, он поднимется к краю вселенной. Лишенный старости и смерти он все будет слышать отчетливо ..35.</p><p>Там следует все, тело прочее созерцать подобным произносимому в пространстве. Тогда он, как и прежде, обретет все плоды, порожденные окружением слуха ..36.</p><p>Поведаю дхарану ума, наделяющую всеми сиддхи, обретя совершенство в ней, о Деви, обретается плод всех сиддхи ..37.</p><p>Ум для людей – причина связанности и освобождения. Поэтому произносящий мантру должен практиковать (его дхарану), если он желает вечного освобождения ..38.</p><p>(Следует созерцать ум), цвета полумесяца, обращеный лицом вниз, пребывающий в сердце. Созерцающий так, за месяц достигнет Света ..39.</p><p>Что бы он ни видел, что бы он ни слышал, каждое это знание (есть ум) -сущность всех чувств ..40.</p><p>За три года он увидит, как происходит постижение в каждом своем чувстве. Для йогинов, приобщенных йоге это (видение) будет отчетливым ..41.</p><p>Созерцая это, как прежде, подобно своему телу, он обретет постижение окружения ума и качество луны ..42.</p><p>Таковы одиннадцать песней. Те кто практикует их, обретает плод всех чувств ..43.</p><p>(Они-) мудрецы, желающие пробудить чувства от связанности желающие освобождения. Принимаемые (чувства) ведут к связанности, освобожденные- к освобождению ..44.</p><p>Когда они (чувства) становятся пребывающими в состоянии растворения (вьяпака), вместе с умом, тогда они постигаются как освобождающие, о Возлюбленная ..45.</p><p>Когда (они направлены на) какие- либо объекты, пребывающие внутри какого- либо места, тогда эти места именуются оковами ..46.</p><p>Такова природа чувств, двух видов, разделяемая на чистую и нечистую, описываемых в учении сиддхийогишвари ..47. [small]Такова в священной «Малини виджайоттара тантре» пятнадцатая глава [/small]</p>',48);r.render=function(t,a,r,i,s,d){return p(),e("div",null,[l])};export default r;export{a as __pageData};
